import{_ as e,o as n,c as l,ag as a}from"./chunks/framework.BZohXCq9.js";const y=JSON.parse('{"title":"Trạng thái triển khai Web (travel-web)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/02-quan-ly-sprint/trang-thai-web.md","filePath":"99-tham-khao/archive/02-quan-ly-sprint/trang-thai-web.md"}'),i={name:"99-tham-khao/archive/02-quan-ly-sprint/trang-thai-web.md"};function d(r,t,o,s,g,h){return n(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="trang-thai-trien-khai-web-travel-web" tabindex="-1">Trạng thái triển khai Web (<code>travel-web</code>) <a class="header-anchor" href="#trang-thai-trien-khai-web-travel-web" aria-label="Permalink to &quot;Trạng thái triển khai Web (`travel-web`)&quot;">​</a></h1><blockquote><p><strong>Cập nhật:</strong> 17/05/2026 — đồng bộ với codebase <code>travel-web</code> tại thời điểm hiện tại.</p></blockquote><p>Tài liệu này là <strong>nguồn sự thật</strong> về tiến độ code web. Khi hoàn thành tính năng mới, cập nhật file này trước khi đóng sprint.</p><h2 id="tong-quan-sprint" tabindex="-1">Tổng quan sprint <a class="header-anchor" href="#tong-quan-sprint" aria-label="Permalink to &quot;Tổng quan sprint&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Sprint</th><th style="text-align:left;">Trạng thái doc</th><th style="text-align:left;">Tiến độ web ước lượng</th></tr></thead><tbody><tr><td style="text-align:left;">Sprint 1 — Nền tảng</td><td style="text-align:left;"><strong>Done</strong></td><td style="text-align:left;"><strong>100%</strong></td></tr><tr><td style="text-align:left;">Sprint 2 — Điểm đến &amp; CMS</td><td style="text-align:left;"><strong>Done</strong></td><td style="text-align:left;"><strong>~95%</strong> (xem ghi chú SP2-02)</td></tr><tr><td style="text-align:left;">Sprint 3 — Khám phá &amp; Tìm kiếm</td><td style="text-align:left;"><strong>In Progress</strong></td><td style="text-align:left;"><strong>~40%</strong></td></tr><tr><td style="text-align:left;">Sprint 4 — Đặt chỗ &amp; Thanh toán</td><td style="text-align:left;"><strong>Upcoming</strong></td><td style="text-align:left;"><strong>~10%</strong></td></tr><tr><td style="text-align:left;">Sprint 5 — Thành viên &amp; Đánh giá</td><td style="text-align:left;"><strong>Upcoming</strong></td><td style="text-align:left;"><strong>0%</strong></td></tr><tr><td style="text-align:left;">Sprint 6 — Tối ưu &amp; Release</td><td style="text-align:left;"><strong>Upcoming</strong></td><td style="text-align:left;"><strong>~15%</strong> (sitemap, SEO metadata)</td></tr></tbody></table><hr><h2 id="sprint-1-—-nen-tang-done" tabindex="-1">Sprint 1 — Nền tảng (Done) <a class="header-anchor" href="#sprint-1-—-nen-tang-done" aria-label="Permalink to &quot;Sprint 1 — Nền tảng (Done)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Hạng mục</th><th style="text-align:left;">Web</th></tr></thead><tbody><tr><td style="text-align:left;">Prisma schema + migrations</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Supabase Auth + <code>@supabase/ssr</code></td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Middleware phân tách Admin (<code>/portal/*</code>) / Public</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Service layer (<code>AuthService</code>, …)</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Admin login + role <code>ADMIN</code></td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Dual cookie session (<code>AUTH_COOKIES.ADMIN</code> / <code>PUBLIC</code>)</td><td style="text-align:left;">✅</td></tr></tbody></table><hr><h2 id="sprint-2-—-quan-tri-noi-dung-điem-đen-done" tabindex="-1">Sprint 2 — Quản trị nội dung &amp; Điểm đến (Done) <a class="header-anchor" href="#sprint-2-—-quan-tri-noi-dung-điem-đen-done" aria-label="Permalink to &quot;Sprint 2 — Quản trị nội dung &amp; Điểm đến (Done)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Task</th><th style="text-align:left;">Web</th><th style="text-align:left;">Ghi chú</th></tr></thead><tbody><tr><td style="text-align:left;">SP2-01 CRUD Điểm đến</td><td style="text-align:left;">✅</td><td style="text-align:left;"><code>admin/destinations</code>, Server Actions</td></tr><tr><td style="text-align:left;">SP2-02 Cloudinary upload</td><td style="text-align:left;">✅</td><td style="text-align:left;">Gallery điểm đến; AC nâng cao (WebP batch, progress) <strong>chưa</strong></td></tr><tr><td style="text-align:left;">SP2-03 Vùng miền (Regions)</td><td style="text-align:left;">✅</td><td style="text-align:left;"><strong>3 miền cố định</strong> — seed <code>mb</code>/<code>mt</code>/<code>mn</code>, <strong>không</strong> CRUD admin</td></tr><tr><td style="text-align:left;">SP2-05 Validation &amp; Toast</td><td style="text-align:left;">✅</td><td style="text-align:left;">Admin forms</td></tr><tr><td style="text-align:left;">SP2-06 Cài đặt hệ thống</td><td style="text-align:left;">✅</td><td style="text-align:left;">System + SEO settings, Home Builder</td></tr><tr><td style="text-align:left;">Home Builder modules</td><td style="text-align:left;">✅</td><td style="text-align:left;">Trending, map, collections, …</td></tr><tr><td style="text-align:left;">Dynamic sitemap</td><td style="text-align:left;">✅</td><td style="text-align:left;"><code>src/app/sitemap.ts</code></td></tr></tbody></table><h3 id="vung-mien-regions-—-quyet-đinh-san-pham" tabindex="-1">Vùng miền (Regions) — quyết định sản phẩm <a class="header-anchor" href="#vung-mien-regions-—-quyet-đinh-san-pham" aria-label="Permalink to &quot;Vùng miền (Regions) — quyết định sản phẩm&quot;">​</a></h3><ul><li>Bảng <code>regions</code> trong DB: <strong>Miền Bắc</strong>, <strong>Miền Trung</strong>, <strong>Miền Nam</strong> (<code>prisma/seed.ts</code>).</li><li>Admin <strong>chọn</strong> vùng khi tạo điểm đến (<code>getRegionsAction</code>); <strong>không</strong> có màn CRUD thêm/sửa/xóa miền.</li><li>Không triển khai <code>POST/PUT/DELETE /api/v1/regions</code> (xem <a href="./sprint-2-quan-tri-diem-den/05-api-design">API Design</a>).</li></ul><hr><h2 id="sprint-3-—-kham-pha-tim-kiem-in-progress" tabindex="-1">Sprint 3 — Khám phá &amp; Tìm kiếm (In Progress) <a class="header-anchor" href="#sprint-3-—-kham-pha-tim-kiem-in-progress" aria-label="Permalink to &quot;Sprint 3 — Khám phá &amp; Tìm kiếm (In Progress)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Task</th><th style="text-align:left;">Web</th><th style="text-align:left;">Ghi chú</th></tr></thead><tbody><tr><td style="text-align:left;">SP3-01 UI Discovery</td><td style="text-align:left;">🔶</td><td style="text-align:left;">Trang <code>/diem-den</code>, <code>/tours</code>, Home modules</td></tr><tr><td style="text-align:left;">SP3-02 Search Autocomplete</td><td style="text-align:left;">❌</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">SP3-03 Filter động</td><td style="text-align:left;">🔶</td><td style="text-align:left;">Lọc tour (search params); chưa đủ rating/loại hình</td></tr><tr><td style="text-align:left;">SP3-04 Interactive Map</td><td style="text-align:left;">🔶</td><td style="text-align:left;">Embed/link trên destination; chưa cluster map</td></tr><tr><td style="text-align:left;">SP3-05 API Search</td><td style="text-align:left;">🔶</td><td style="text-align:left;"><code>TourService.searchListings</code>, API <code>GET /api/v1/tours</code></td></tr><tr><td style="text-align:left;">Quản lý Tour (admin + public)</td><td style="text-align:left;">✅</td><td style="text-align:left;">Đã có trước khi đóng hết backlog SP3 — xem ma trận tính năng</td></tr></tbody></table><hr><h2 id="sprint-4-—-đat-cho-thanh-toan-upcoming" tabindex="-1">Sprint 4 — Đặt chỗ &amp; Thanh toán (Upcoming) <a class="header-anchor" href="#sprint-4-—-đat-cho-thanh-toan-upcoming" aria-label="Permalink to &quot;Sprint 4 — Đặt chỗ &amp; Thanh toán (Upcoming)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Task</th><th style="text-align:left;">Web</th><th style="text-align:left;">Ghi chú</th></tr></thead><tbody><tr><td style="text-align:left;">SP4-01 Booking Engine</td><td style="text-align:left;">❌</td><td style="text-align:left;">Model có; không có <code>booking.create</code></td></tr><tr><td style="text-align:left;">SP4-02 Checkout UI</td><td style="text-align:left;">❌</td><td style="text-align:left;"><code>booking-widget</code> chưa gắn action</td></tr><tr><td style="text-align:left;">SP4-03 VNPay/MoMo</td><td style="text-align:left;">❌</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">SP4-04 Order Management (Admin)</td><td style="text-align:left;">🔶</td><td style="text-align:left;">List đọc-only <code>admin/bookings</code></td></tr><tr><td style="text-align:left;">SP4-05 Email đặt chỗ</td><td style="text-align:left;">❌</td><td style="text-align:left;">Auth email qua Supabase SMTP</td></tr></tbody></table><hr><h2 id="auth-khach-hang-bo-sung-ngoai-sprint-cu" tabindex="-1">Auth khách hàng (bổ sung ngoài sprint cũ) <a class="header-anchor" href="#auth-khach-hang-bo-sung-ngoai-sprint-cu" aria-label="Permalink to &quot;Auth khách hàng (bổ sung ngoài sprint cũ)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Tính năng</th><th style="text-align:left;">Web</th></tr></thead><tbody><tr><td style="text-align:left;">Đăng ký / đăng nhập email</td><td style="text-align:left;">✅ <code>/dang-ky</code>, <code>/dang-nhap</code></td></tr><tr><td style="text-align:left;">Xác nhận email + gửi lại</td><td style="text-align:left;">✅ <code>/dang-ky/xac-nhan-email</code></td></tr><tr><td style="text-align:left;">Quên / đặt lại mật khẩu</td><td style="text-align:left;">✅ <code>/quen-mat-khau</code>, <code>/dat-lai-mat-khau</code></td></tr><tr><td style="text-align:left;">Đăng nhập Google OAuth</td><td style="text-align:left;">✅ Supabase + <code>/auth/callback</code></td></tr><tr><td style="text-align:left;">Đồng bộ profile Prisma</td><td style="text-align:left;">✅ <code>ensureUserProfile</code> (tên, avatar Google)</td></tr><tr><td style="text-align:left;">Tài khoản <code>/tai-khoan</code></td><td style="text-align:left;">🔶</td></tr><tr><td style="text-align:left;">Đơn của tôi <code>/don-dat</code></td><td style="text-align:left;">🔶</td></tr></tbody></table><p>Chi tiết: <a href="./../01-nen-tang-he-thong/04-bao-mat-xac-thuc">Bảo mật &amp; Xác thực</a>.</p><hr><h2 id="chua-trien-khai-placeholder" tabindex="-1">Chưa triển khai / placeholder <a class="header-anchor" href="#chua-trien-khai-placeholder" aria-label="Permalink to &quot;Chưa triển khai / placeholder&quot;">​</a></h2><ul><li>Thanh toán, khách sạn (<code>/khach-san</code>), reviews, newsletter backend, liên hệ <code>/lien-he</code></li><li>CMS pháp lý admin (<code>LegalContent</code>) — trang public tĩnh i18n</li><li>Mobile app (Phase 2 — Deferred)</li></ul><hr><p><em>Ký hiệu: ✅ hoàn thành · 🔶 một phần · ❌ chưa có</em></p>',28)])])}const f=e(i,[["render",d]]);export{y as __pageData,f as default};
